      B6: 'كاتب المحتوى', C6: writerName || '',
      B7: 'كود كاتب المحتوى', C7: writerCode || '',
      B8: 'نوع الحمله', C8: campaignTypeName || '',
      B9: 'معنى العنصر داخل MZJ', C9: '',
