    try{ const ci=campaignsList().findIndex(c=>norm(c.id||c.docId||c.campaignId)===norm(loc.campaign.id)); if(ci>=0) campaigns[ci]={...campaigns[ci], departmentTasks:next}; }catch(_){ }
