        try{ showToast('تم اعتماد الهيكل وتوزيع التاسكات على اليوزرات.'); }catch(_){}
        try{ document.querySelectorAll('.structure-review-popup,.structure-review-modal').forEach(el=>el.remove()); }catch(_){}
