  const campaignOf = task => { try{ return typeof campaignForTask === 'function' ? (campaignForTask(task) || {}) : ((window.campaigns || []).find(c => S(c.id || c.campaignId || c.campaignCode) === S(task?.campaignId || task?.campaignCode)) || {}); }catch(_){ return {}; } };
