  const isTemplateTask = task => roleOf(task)==='content' && !!(task?.contentTemplateTask || task?.taskTemplate || task?.contentTaskTemplate || task?.approvedContentTemplate || N([task?.taskType, task?.source, task?.id, task?.taskId].join(' ')).includes(N('task template')) || N([task?.taskType, task?.source, task?.id, task?.taskId].join(' ')).includes('tasktemplate') || N([task?.taskType, task?.source, task?.id, task?.taskId].join(' ')).includes('contenttemplate') || N(task?.taskType).includes(N('قالب')));
  const isStructureTask = task => roleOf(task)==='content' && !isTemplateTask(task) && !!(task?.needsStructureUpload || task?.structureRequestTask || task?.structureBundleTask || task?.sourceRequestStep === 'campaign_request_data' || N([task?.taskType, task?.structureTaskLabel, task?.creative, task?.product, task?.source].join(' ')).includes(N('هيكل')) || N([task?.taskType, task?.structureTaskLabel, task?.creative, task?.product, task?.source].join(' ')).includes('structure'));
