    ['shooting','design','montage'].forEach(role=>{const list=exec.filter(t=>roleOf(t)===role); if(list.length) groups.push(dashSection(role,roleLabel(role),list,`<div class="v559-exec-grid">${list.map(execCard).join('')}</div>`,role==='shooting'?'📸':role==='design'?'🎨':'🎬'));});
