  function raidriveFileUrl(path){
    const p=S(path);
    if(!p) return '';
    return 'file:///' + p.replace(/\\/g,'/').replace(/^([A-Za-z]):/, '$1:');
  }
  async function copyTextValue(text){
    const value=S(text);
    if(!value){ alert('المسار غير محفوظ على هذا التاسك. أعد إنشاء فولدرات الخام ثم احفظ الحملة.'); return false; }
    try{
      if(navigator.clipboard && window.isSecureContext){
        await navigator.clipboard.writeText(value);
        toast('تم نسخ المسار.');
        return true;
      }
    }catch(_){ }
    try{
      const ta=document.createElement('textarea');
      ta.value=value;
      ta.setAttribute('readonly','readonly');
      ta.style.position='fixed';
      ta.style.top='-1000px';
      document.body.appendChild(ta);
      ta.focus();
      ta.select();
      const ok=document.execCommand('copy');
      ta.remove();
      if(ok){ toast('تم نسخ المسار.'); return true; }
    }catch(_){ }
    window.prompt('انسخ المسار وافتحه في Windows Explorer:', value);
    return false;
  }
  function openRaidrivePath(path,url){
    const p=S(path);
    if(!p){
      alert('مسار RaiDrive غير محفوظ على هذا التاسك. أعد إنشاء فولدرات الخام ثم احفظ الحملة.');
      if(url) window.open(url,'_blank');
      return;
    }
    // ننسخ المسار دائمًا كاحتياطي لأن Chrome قد يمنع فتح file:// من صفحة ويب.
    copyTextValue(p);
    const fileUrl=raidriveFileUrl(p);
    try{
      const a=document.createElement('a');
      a.href=fileUrl;
      a.target='_blank';
      a.rel='noopener';
      document.body.appendChild(a);
      a.click();
      a.remove();
      toast('لو الفولدر لم يفتح، افتح Windows Explorer والصق المسار المنسوخ.');
      return;
    }catch(_){ }
    try{ window.open(fileUrl,'_blank'); return; }catch(_){ }
    if(url) window.open(url,'_blank');
  }
  function templateData(t){
    const src=t.approvedContentTemplate||t.contentTaskTemplate||t.taskTemplate||{};
    const fields=['الاسم المقترح للكرييتيف','الهدف','الرسالة الأساسية','الهوك','السكريبت الأساسي','CTA','الكابشن','هاشتاج'];
    const aliases={
      'الاسم المقترح للكرييتيف':['suggestedCreativeName','creativeName','creativeTitle','title'],
      'الهدف':['goal','objective','contentGoal'],
      'الرسالة الأساسية':['message','mainMessage','coreMessage','الرسالة'],
      'الهوك':['hook'],
      'السكريبت الأساسي':['script','mainScript','basicScript'],
      'CTA':['cta','callToAction'],
      'الكابشن':['caption'],
      'هاشتاج':['hashtags','hashtag','hashTags','هاشتاجات']
    };
    const out={};
    const setVal=(label,val)=>{ if(!S(out[label]) && S(val)) out[label]=S(val); };
    fields.forEach(f=>{
      setVal(f,src[f]);
      setVal(f,src[norm(f)]);
      A(aliases[f]).forEach(k=>{ setVal(f,src[k]); setVal(f,src[norm(k)]); });
    });
    A(src.taskTemplateFields).forEach(f=>{
      const lab=S(f.label||f.key||f.name);
      const val=S(f.value||f.text||f.content);
      fields.forEach(x=>{ if(norm(lab)===norm(x) || A(aliases[x]).some(a=>norm(lab)===norm(a))) setVal(x,val); });
    });
    A(src.parsedRows).forEach(row=>{
      A(row.taskTemplateFields).forEach(f=>{
        const lab=S(f.label||f.key||f.name), val=S(f.value||f.text||f.content);
        fields.forEach(x=>{ if(norm(lab)===norm(x) || A(aliases[x]).some(a=>norm(lab)===norm(a))) setVal(x,val); });
      });
      const raw=row.raw||row||{};
      fields.forEach(x=>{ setVal(x,raw[x]); A(aliases[x]).forEach(a=>setVal(x,raw[a])); });
    });
    if(!Object.values(out).some(Boolean)){
      A(src.sheetRows).forEach(r=>{const cells=r.cells||{}; const lab=S(cells.A||cells.a||''); const val=S(cells.B||cells.b||''); fields.forEach(f=>{if(norm(lab)===norm(f))setVal(f,val);});});
    }
    fields.forEach(f=>{ if(!Object.prototype.hasOwnProperty.call(out,f)) out[f]=''; });
    return out;
  }
